Component({
  options: {
    styleIsolation: 'apply-shared'
  },
  properties: {
    type: {
      type: Number,
      value: 1
    },
    navs: {
      type: Array,
      value: [],
      observer(newVal) {
        const newNavs = JSON.parse(JSON.stringify(newVal))
        const navList = []
        let rowNum = 0
        switch (this.data.type) {
          case 1:
            rowNum = 4
            break
          case 2:
            rowNum = 5
            break
          default:
            rowNum = 4
        }
        for (let i = 0; i < newNavs.length; i++) {
          if (i % rowNum === 0) {
            navList.push([])
          }
          navList[navList.length - 1].push(newNavs[i])
        }
        this.setData({
          navListData: navList
        })
      }
    },
    // 导航上方的图片
    navTopPic: {
      type: String,
      value: ''
    },
    // 导航是否向上偏移
    navOffset: {
      type: Boolean,
      value: false
    },
    // 导航阴影色
    shadowColor: {
      type: String,
      value: '#E1D9B5'
    },
    backgroundType: {
      type: Number,
      value: 0
    },
    backgroundVal: {
      type: Array,
      value: []
    }

  },
  data: {
    navListData: []
  },
  methods: {
    clickNav(e) {
      const href = e.currentTarget.dataset.href
      if (!href) {
        return
      }
      this.triggerEvent('dealPath', {
        data: href
      })
    }
  }
})
